def transform(grid):
    rows=len(grid)
    cols=len(grid[0])
    segments=4
    seg_size=4
    boundaries=[0,5,10,15,20]
    # compute totals
    totals=[0]*segments
    data_by_row=[[] for _ in range(rows)]
    for r,row in enumerate(grid):
        seg_contents=[]
        for s in range(segments):
            start=1+s*5
            segment_cells=row[start:start+4]
            seg_contents.append(segment_cells)
            totals[s]+=segment_cells.count(4)
        data_by_row[r]=seg_contents
    # target totals ascending
    sorted_totals=sorted(totals)
    # We'll create empty segment totals counters
    remaining=sorted_totals[:]
    # Build output segments empty
    out_segments=[ [ [0]*seg_size for _ in range(rows) ] for _ in range(segments) ]
    # We'll iterate rows and within row iterate relative positions to place 4 preserving per-row counts maybe simplistic
    # Collect all 4s as list of (row, relpos) for each occurrence, maintaining original order left to right.
    occurrences=[]
    for r in range(rows):
        for rel in range(seg_size):
            for s in range(segments):
                if data_by_row[r][s][rel]==4:
                    occurrences.append((r,rel))
    # Fill segments from left to right until reach remaining counts
    seg_index=0
    idx_in_seg=[0]*segments  # count placed so far
    for occ in occurrences:
        r,rel=occ
        # advance seg_index until still capacity
        while seg_index<segments and idx_in_seg[seg_index]>=remaining[seg_index]:
            seg_index+=1
        if seg_index>=segments:
            print("overflow")
            break
        # place 4
        out_segments[seg_index][r][rel]=4
        idx_in_seg[seg_index]+=1
    # Build output grid
    new_grid=[]
    for r in range(rows):
        row=[]
        for c in range(cols):
            if c in boundaries:
                row.append(3)
            else:
                row.append(0)
        new_grid.append(row)
    for s in range(segments):
        start=1+s*5
        for r in range(rows):
            for rel in range(seg_size):
                if out_segments[s][r][rel]==4:
                    new_grid[r][start+rel]=4
    return new_grid
